Rule.Source:
 
  
  import sailpoint.object.Identity;
  import sailpoint.object.Identity.WorkgroupNotificationOption;
  import sailpoint.object.QueryOptions;
  import sailpoint.object.Filter;
  import sailpoint.tools.Message.Type;
  import sailpoint.tools.Message;
  import org.apache.commons.logging.Log;
  import org.apache.commons.logging.LogFactory;
  //Method to create Workgroup
  public void createNewWorkgroup(String[] wgAddMembers, String wgName){
    log.debug("Ascension-Rule-Workgroup-Creation-And-Member-Population || Entering method createNewWorkgroup");
    Identity newWG = new Identity();
    newWG.setName(wgName);
    newWG.setWorkgroup(true);
    newWG.setNotificationOption(Identity.WorkgroupNotificationOption.MembersOnly);
    newWG.setDescription("");
    context.saveObject(newWG);
    context.commitTransaction();       
    newlyCreatedWGS.add(wgName);
//    context.decache(newWG);
    addMembersToWorkgroup(wgAddMembers, wgName);
    log.debug("Ascension-Rule-Workgroup-Creation-And-Member-Population || Exiting method createNewWorkgroup");
  }
  //Method to addMemmbers to the WG 
  public void addMembersToWorkgroup(String[] wgAddMembers, wgName){
    log.debug("Ascension-Rule-Workgroup-Creation-And-Member-Population || Entering method addMembersToWorkgroup");
    List eachErrorList = new ArrayList();
    List successList = new ArrayList();
    Identity workGroupObj = context.getObjectByName(Identity.class, wgName);
    if(null!=workGroupObj){
      for(String member:wgAddMembers) {	
        member = member.trim();
        QueryOptions qo = new QueryOptions();   
        qo.addFilter(Filter.or(Filter.eq("name",member.toLowerCase()),Filter.eq("name",member.toUpperCase())));
        List identities = context.getObjects(Identity.class, qo);
        if(identities!=null && identities.size()>0 && identities.size()<2)
        {	
          Identity identity = context.getObjectByName(Identity.class, identities.get(0).getName());
          if(null == identity){
            String errString = member+"-Doesn't Exist in IIQ";   
            eachErrorList.add(errString);
            errorMap.put(workGroupObj.getName(),eachErrorList);
          }else if(!identity.isInactive()){
            if(identity.isCorrelated()){
              identity.add(workGroupObj);
              context.saveObject(identity);
              context.commitTransaction();         
              successList.add(member);
              successMap.put(workGroupObj.getName(),successList);
//              context.decache(identity);
            }else{
              String errString = member+"-Orphan Identity";         
              eachErrorList.add(errString);
              errorMap.put(workGroupObj.getName(),eachErrorList);                          
            }
          }else{
            String errString = member+"-Inactive in IIQ";         
            eachErrorList.add(errString);
            errorMap.put(workGroupObj.getName(),eachErrorList);
          }
        }else{         
          String errString = member+"-Doesn't Exist in IIQ";         
          eachErrorList.add(errString);
          errorMap.put(workGroupObj.getName(),eachErrorList);
        }
      }
    }
    log.debug("Ascension-Rule-Workgroup-Creation-And-Member-Population || Exiting method addMembersToWorkgroup");
  }
  //::::  Rule Starts :::::::::
  String className = "Ascension-Rule-Workgroup-Creation-And-Member-Population";
  Log log = LogFactory.getLog(className);
  log.debug("Ascension-Rule-Workgroup-Creation-And-Member-Population || Entering Rule");
  String fileLocation = null;
  String createNewWGString = null;
  List notProcessed = new ArrayList();
  Map errorMap = new HashMap();
  Map successMap = new HashMap();
  List newlyCreatedWGS = new ArrayList();
  BufferedReader bufferReader = null;
  if(null!=config){
    fileLocation = config.get("filePath");
    createNewWGString = config.get("createNewWG"); 
    try{
      if(null!=fileLocation){
        bufferReader = new BufferedReader(new FileReader(fileLocation));
        int lineCount=0;
        if(null!=bufferReader){
          while(null != (line = bufferReader.readLine()))
          {   
            lineCount++;
            if(line.startsWith("WorkgroupName")){
              log.debug("Ascension-Rule-Workgroup-Creation-And-Member-Population || Skipping execution of line : " + lineCount);
              continue;
            }else{ 
              String[] details = line.split("\\|",-1);
              int size = details.length;
              if(size <= 1){
                log.debug("Ascension-Rule-Workgroup-Creation-And-Member-Population || Data missing from line : " + lineCount);
                notProcessed.add(lineCount);
                continue;
              }else{
                String wgName = details[0];
                String[] wgAddMembers = details[1].split(",");
                if(null == wgAddMembers || "None".equals(wgAddMembers[0]) || "none".equals(wgAddMembers[0])){
                  log.debug("Ascension-Rule-Workgroup-Creation-And-Member-Population || Add Members list empty from line : " + lineCount);
                }else{
                  Identity workGroupObj = context.getObjectByName(Identity.class, wgName.trim());
                  if(null == workGroupObj  && createNewWGString.equalsIgnoreCase("true")){
                    createNewWorkgroup(wgAddMembers,wgName);			
                  }else{
                    addMembersToWorkgroup(wgAddMembers,wgName);
                  }
                }
              }
            }
          }      
        }
      }
    } catch(IOException e){     
      log.error("Ascension-Rule-Workgroup-Creation-And-Member-Population || Exception "+e.getMessage());
      taskResult.addMessage(new Message(Message.Type.Error, "Exception: "+e.getMessage(), null));
    }finally{
      if(null!=bufferReader){
        bufferReader.close();            
      }
    }
  }
  taskResult.setAttribute("newlyCreatedWGS",newlyCreatedWGS); 
  taskResult.setAttribute("successMap",successMap); 
  taskResult.setAttribute("errorMap",errorMap); 
  taskResult.setAttribute("notProcessed",notProcessed);
  log.debug("Ascension-Rule-Workgroup-Creation-And-Member-Population || Exiting Rule");
  return "Success";
